parameters.jsonBody:
={
  "urls": ["{{ $json.url }}"],
  "prompt": "Extract the primary contact and company info from this page. If it's a directory listing of multiple companies, return the FIRST company only — we'll call you again for the others. Use empty string for any field you can't confidently fill from this page.",
  "schema": {
    "type": "object",
    "properties": {
      "company":  { "type": "string", "description": "Business / organization name" },
      "name":     { "type": "string", "description": "Primary contact person name; falls back to company name if no person is listed" },
      "email":    { "type": "string", "description": "Best public contact email" },
      "phone":    { "type": "string", "description": "Phone in international format if shown" },
      "category": { "type": "string", "description": "Industry / niche this company operates in" },
      "location": { "type": "string", "description": "City + country if shown" },
      "summary":  { "type": "string", "description": "One-line summary of what this company does" }
    },
    "required": ["company"]
  }
}
